// ─── MAIN APP ───
export default function App() {
  const [page, setPage] = useState("home");

  const changePage = (p) => {
    setPage(p);
    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  const renderPage = () => {
    switch (page) {
      case "home": return <HomePage setPage={changePage} />;
      case "events": return <EventsPage />;
      case "gallery": return <GalleryPage />;
      case "mixes": return <MixesPage />;
      case "records": return <RecordsPage />;
      default: return <HomePage setPage={changePage} />;
    }
  };

  return (
    <div style={{ background: BG_DARK, minHeight: "100vh", color: TEXT_PRIMARY }}>
      <style>{globalCSS}</style>
      <Nav currentPage={page} setPage={changePage} />
      {renderPage()}
      <Footer />
    </div>
  );
}
